//! Cross-engine COSE_Sign1 conformance (§9.2): the Rust engine must reproduce
//! the frozen `vectors/cose/*.json` (generated by the Python oracle) byte-for-byte
//! and verify them.

use std::path::Path;

use ed25519_dalek::{SigningKey, VerifyingKey};
use gmeow_gts::cose::{sign_id, signature_kid, verify_sig, SigStatus};

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).expect("hex"))
        .collect()
}

fn arr32(v: Vec<u8>) -> [u8; 32] {
    v.try_into().expect("32 bytes")
}

#[test]
fn cose_sign1_vectors_round_trip() {
    let dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../vectors/cose");
    let mut count = 0;
    for entry in std::fs::read_dir(&dir).expect("vectors/cose must exist") {
        let path = entry.unwrap().path();
        if path.extension().and_then(|e| e.to_str()) != Some("json") {
            continue;
        }
        let json: serde_json::Value =
            serde_json::from_slice(&std::fs::read(&path).unwrap()).unwrap();
        let seed = arr32(unhex(json["seed"].as_str().unwrap()));
        let pub32 = arr32(unhex(json["pub"].as_str().unwrap()));
        let kid = json["kid"].as_str().unwrap();
        let frame_id = unhex(json["frame_id"].as_str().unwrap());
        let expected = unhex(json["cose"].as_str().unwrap());

        // Deterministic Ed25519: signing reproduces the frozen bytes exactly.
        let sk = SigningKey::from_bytes(&seed);
        assert_eq!(
            sign_id(&frame_id, &sk, kid),
            expected,
            "sign mismatch in {path:?}"
        );

        // The kid round-trips out of the COSE structure.
        assert_eq!(signature_kid(&expected).as_deref(), Some(kid));

        // Verification against the public key succeeds.
        let vk = VerifyingKey::from_bytes(&pub32).unwrap();
        assert_eq!(verify_sig(&expected, &frame_id, &vk), SigStatus::Valid);

        // A tampered frame id (or signature) fails.
        let mut tampered = frame_id.clone();
        tampered.push(0xff);
        assert_eq!(verify_sig(&expected, &tampered, &vk), SigStatus::Invalid);

        count += 1;
    }
    assert!(
        count >= 2,
        "expected at least two COSE vectors, found {count}"
    );
}
